/* Library Function - Single Match
    wcsncpy

   Libraries: Visual Studio 2015 Release, Visual Studio 2017 Release, Visual Studio 2019 Release */

wchar_t * __cdecl wcsncpy(wchar_t *_Dest,wchar_t *_Source,size_t _Count)

{
  wchar_t wVar1;
  wchar_t *pwVar2;
  longlong lVar3;

  if (_Count != 0) {
    pwVar2 = _Dest;
    do {
      wVar1 = *(wchar_t *)(((longlong)_Source - (longlong)_Dest) + (longlong)pwVar2);
      *pwVar2 = wVar1;
      pwVar2 = pwVar2 + 1;
      if (wVar1 == L'\0') break;
      _Count = _Count - 1;
    } while (_Count != 0);
    if ((_Count != 0) && (lVar3 = _Count - 1, lVar3 != 0)) {
      for (; lVar3 != 0; lVar3 = lVar3 + -1) {
        *pwVar2 = L'\0';
        pwVar2 = pwVar2 + 1;
      }
    }
  }
  return _Dest;
}
